(function(){"use strict";let s=null;self.onmessage=n=>{const{type:e}=n.data;if(e==="init")s=n.data.positions;else if(e==="sort"){if(!s)return;const{vx:i,vy:c,vz:o}=n.data,f=g(s,s.length/3,i,c,o);self.postMessage({type:"sorted",indices:f},[f.buffer])}};function g(n,e,i,c,o){let l=-1/0,a=1/0;for(let t=0;t<e;t++){const r=n[t*3]*i+n[t*3+1]*c+n[t*3+2]*o;r>l&&(l=r),r<a&&(a=r)}const S=65535/(l-a||1),U=new Uint32Array(65536),y=new Uint32Array(e);for(let t=0;t<e;t++){const r=(n[t*3]*i+n[t*3+1]*c+n[t*3+2]*o-a)*S|0;y[t]=r,U[r]++}const u=new Uint32Array(65536);for(let t=1;t<65536;t++)u[t]=u[t-1]+U[t-1];const d=new Uint32Array(e);for(let t=0;t<e;t++)d[u[y[t]]++]=t;return d}})();
